// ============================================================
// EXTRACTION FACTURE PAR REGEX - Urban Hit (Batch VT Consult)
// ============================================================

// Assurer que le texte est bien une chaîne de caractères
const text = String($json.text || $json.content || $json.data || '');

// Récupérer le binaire PDF depuis le noeud Gmail
const gmailItem = $item(0).$node['Récupérer Emails VT Consult'];
const binData = (gmailItem && gmailItem.binary) ? gmailItem.binary : {};
const binaryKeys = Object.keys(binData);

const pdfKey = binaryKeys.find(k => {
  const b = binData[k];
  return (b.mimeType || '').toLowerCase().includes('pdf') || (b.fileName || '').toLowerCase().endsWith('.pdf');
}) || binaryKeys[0];

const pdf_base64 = pdfKey ? (binData[pdfKey].data || null) : null;

// ---- Helpers ----

function extract(patterns, str) {
  if (typeof str !== 'string') return null;
  for (const p of patterns) {
    const m = str.match(p);
    if (m && m[1]) return m[1].trim();
  }
  return null;
}

function parseAmount(s) {
  if (typeof s !== 'string') return null;
  let cleaned = s.replace(/[€$\s\u00a0\u202f]/g, '');
  if (/^[\d.]+,\d{2}$/.test(cleaned)) {
    cleaned = cleaned.replace(/\./g, '').replace(',', '.');
  } else if (/^[\d,]+\.\d{2}$/.test(cleaned)) {
    cleaned = cleaned.replace(/,/g, '');
  } else {
    cleaned = cleaned.replace(/[,\.]/g, (m, offset, str) => {
      return offset === str.lastIndexOf(m) ? '.' : '';
    });
  }
  const n = parseFloat(cleaned);
  return isNaN(n) ? null : Math.round(n * 100) / 100;
}

function parseDate(s) {
  if (typeof s !== 'string') return null;
  s = s.trim();
  const months = {
    'janvier':'01','février':'02','fevrier':'02','mars':'03','avril':'04',
    'mai':'05','juin':'06','juillet':'07','août':'08','aout':'08',
    'septembre':'09','octobre':'10','novembre':'11','décembre':'12','decembre':'12',
    'jan':'01','fév':'02','fev':'02','mar':'03','avr':'04',
    'jun':'06','jul':'07','sep':'09','oct':'10','nov':'11','déc':'12','dec':'12'
  };
  const fr = s.match(/(\d{1,2})\s+([a-zéûôêàùïîè]+)\.?\s+(\d{4})/i);
  if (fr) {
    const m = months[fr[2].toLowerCase()];
    if (m) return `${fr[3]}-${m}-${fr[1].padStart(2,'0')}`;
  }
  const num = s.match(/(\d{1,2})[\/.\-](\d{1,2})[\/.\-](\d{4})/);
  if (num) return `${num[3]}-${num[2].padStart(2,'0')}-${num[1].padStart(2,'0')}`;
  const iso = s.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (iso) return iso[0];
  return null;
}

// ---- Extraction ----

// Fournisseur = VT Consult (connu)
const supplier_name = 'VT Consult';

const reference = extract([
  /(?:facture\s*n[°o°]?\.?|n[°o°]\.?\s*(?:de\s*)?facture|invoice\s*(?:no?\.?|number|#|n[°o°]?\.?)|numéro\s*(?:de\s*facture)?|réf(?:érence)?\s*(?:facture)?)\s*[:\s#]*([A-Z0-9][A-Z0-9\-\/_. ]{1,30})/i,
  /N[°o°]\s*[:#\s]*([A-Z0-9][A-Z0-9\-\/_. ]{1,25})/i,
  /([A-Z]{1,5}[-_]\d{4,12})/,
  /\b(\d{4}[-_][A-Z0-9]{3,}|[A-Z]{2,5}\d{4,})/,
], text);

const issued_date_raw = extract([
  /(?:date\s*(?:de\s*(?:la\s*)?)?facture|date\s*d[''`]?émission|date\s*de\s*facturation|émis\s*(?:le|:)|facturé\s*le|date\s*de\s*création|date\s*facture)\s*[:\s]*([^\n]{5,35})/i,
  /(?:^|\b)(?:le|date)\s*[:\s]*(\d{1,2}[\s\/\.\-][\w]{2,10}[\s\/\.\-]\d{4})/im,
], text);

const due_date_raw = extract([
  /(?:date\s*(?:d[''`])?échéance|échéance|date\s*limite\s*(?:de\s*)?paiement|payable\s*(?:le|avant\s*le)|règlement\s*(?:le|au)|à\s*payer\s*(?:le|avant\s*le))\s*[:\s]*([^\n]{5,35})/i,
], text);

const today = new Date().toISOString().split('T')[0];
const issued_date = parseDate(issued_date_raw) || today;
const due_date = parseDate(due_date_raw) || issued_date;

const amount_ht_raw = extract([
  /(?:total\s*HT|montant\s*(?:total\s*)?HT|sous[\s\-]?total\s*HT|net\s*(?:avant\s*)?(?:TVA|taxes?)|total\s*hors\s*(?:TVA|taxes?))\s*[:\s]*([\d\s\u00a0\u202f.,]+(?:\s*€|\s*EUR)?)/i,
  /HT\s*[:\s]([\d\s\u00a0.,]+(?:\s*€|\s*EUR)?)/i,
], text);

const amount_ttc_raw = extract([
  /(?:total\s*(?:général\s*)?TTC|net\s*à\s*payer|montant\s*(?:total\s*)?(?:à\s*)?(?:payer|régler|dû)|total\s*(?:à\s*)?(?:payer|régler)|total\s*(?:facture|final))\s*[:\s]*([\d\s\u00a0\u202f.,]+(?:\s*€|\s*EUR)?)/i,
  /TTC\s*[:\s]([\d\s\u00a0.,]+(?:\s*€|\s*EUR)?)/i,
  /(?:net\s*à\s*payer|à\s*payer\s*:)\s*([\d\s\u00a0.,]+(?:\s*€|\s*EUR)?)/i,
], text);

const amount_ht = parseAmount(amount_ht_raw);
const amount_ttc = parseAmount(amount_ttc_raw);

const subject = (gmailItem.json && gmailItem.json.subject) || 'Sans sujet';

return {
  json: {
    company_handle: '@urban.hit',
    supplier_name,
    reference: reference ? reference.replace(/\s+$/, '') : null,
    issued_date,
    due_date,
    amount_ht,
    amount_ttc: amount_ttc || 0,
    pdf_base64,
    status: 'PENDING',
    _debug: {
      email_subject: subject,
      pdf_text_preview: text.substring(0, 300)
    }
  }
};

// Garde uniquement le premier binaire PDF, supprime les autres (PNG, images, etc.)
const bin = $input.item.binary || {};
const allKeys = Object.keys(bin);
const pdfKey = allKeys.find(k => {
  const b = bin[k];
  return (b.mimeType || '').toLowerCase().includes('pdf') || (b.fileName || '').toLowerCase().endsWith('.pdf');
});

if (!pdfKey) {
  return [];
}

return {
  json: $input.item.json,
  binary: { pdf: bin[pdfKey] }
};
